Action.Str:
if (intent != void && intent != null) {
    android.os.Bundle extras = intent.getExtras();

    if ((extras != null) && (extras.getsize() > 1)) {
        for (String key : extras.keySet()) {
            Object obj = extras.get(key);
            String value = (obj == null) ? "" : obj.toString();

            if (!key.isEmpty()) {
                setLocal("%" + key, value);
            }
        }
    }
}

